function solve(s) {
    const N = s.length;
    if (N === 0) {
        return 0;
    }

    // Count the number of '1's
    let countOnes = 0;
    for (let i = 0; i < N; i++) {
        if (s[i] === '1') {
            countOnes++;
        }
    }

    // Cost 1: Target 0^N (All Zeros)
    // We must flip all '1's to '0's.
    const costAllZeros = countOnes;

    // Cost 2: Target 1^N (All Ones)
    // We must flip all '0's to '1's.
    const costAllOnes = N - countOnes;

    // Cost 3: Target a coherent string with at most one '1' (0* 1? 0*)
    let costAtMostOneOne;

    if (countOnes === 0) {
        // s is all zeros. It is already coherent. 
        // To achieve exactly one '1', we need 1 flip.
        // Since we are looking for the minimum, targeting 0^N (Cost 0) is better.
        // However, if we calculate this based on the derived formula (0* 1? 0*), 
        // the minimum cost to achieve the structure (which includes 0^N) is 0.
        costAtMostOneOne = 0; 
    } else {
        // We have at least one '1'. We keep one existing '1' (cost 0 for that position)
        // and flip all other (countOnes - 1) '1's to '0's.
        costAtMostOneOne = countOnes - 1;
